'use client';

import { useState, useEffect } from 'react';
import { Bell, CheckCheck, Trash2 } from 'lucide-react';
import { useRouter } from '@/i18n/navigation';
import { getNotifications, markAsRead, markAllAsRead, deleteAllNotifications } from '@/api/notifications';
import type { Notification } from '@/api/notifications';

const NOTIF_LOGO = '/assets/img/icons/NotifLogo.svg';

const typeLabels: Record<string, string> = {
    appointment_confirmed: 'Qabul tasdiqlandi',
    appointment_cancelled: 'Qabul bekor qilindi',
    appointment_reminder: 'Eslatma',
    payment_received: "To'lov qabul qilindi",
    review_received: 'Yangi baho',
    profile_approved: 'Profil tasdiqlandi',
    profile_rejected: 'Profil rad etildi',
    system_message: 'Tizim xabari',
};

const NotificationsPage = () => {
    const router = useRouter();
    const [notifications, setNotifications] = useState<Notification[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchNotifications();
    }, []);

    const fetchNotifications = async () => {
        try {
            setLoading(true);
            const data = await getNotifications();
            setNotifications(data);
        } catch (err: any) {
            console.error('Notifications error:', err?.response?.status, err?.response?.data);
        } finally {
            setLoading(false);
        }
    };

    const handleClick = async (n: Notification) => {
        if (!n.is_read) {
            await markAsRead(n.id);
            setNotifications(prev => prev.map(x => x.id === n.id ? { ...x, is_read: true } : x));
        }
    };

    const handleMarkAll = async () => {
        await markAllAsRead();
        setNotifications(prev => prev.map(x => ({ ...x, is_read: true })));
    };

    const handleDeleteAll = async () => {
        if (notifications.length === 0) return;

        const confirmed = window.confirm("Barcha bildirishnomalarni o'chirishni tasdiqlaysizmi?");
        if (confirmed) {
            try {
                await deleteAllNotifications();
                setNotifications([]);
            } catch (err) {
                console.error("Delete all error:", err);
            }
        }
    };

    const formatTime = (dateString: string) => {
        // Ensure UTC parsing - add Z if not present
        const utcString = dateString.endsWith('Z') || dateString.includes('+') ? dateString : dateString + 'Z';
        const date = new Date(utcString);
        const now = new Date();
        const diff = now.getTime() - date.getTime();
        const mins = Math.floor(diff / 60000);
        const hours = Math.floor(diff / 3600000);
        const days = Math.floor(diff / 86400000);
        if (mins < 1) return 'Hozir';
        if (mins < 60) return `${mins} daqiqa oldin`;
        if (hours < 24) return `${hours} soat oldin`;
        return `${days} kun oldin`;
    };

    const unreadCount = notifications.filter(n => !n.is_read).length;

    return (
        <div className="min-h-screen bg-[#f5f7fb] flex flex-col">
            {/* Header */}
            <div className="bg-white px-4 py-5 flex items-center justify-between sticky top-0 z-20 shadow-sm">
                <div className="flex items-center gap-3">
                    <button
                        onClick={() => router.back()}
                        className="w-10 h-10 flex items-center justify-center bg-[#1D1D2B] rounded-full"
                    >
                        <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
                            <path d="M15 18L9 12L15 6" stroke="white" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" />
                        </svg>
                    </button>
                    <div>
                        <h1 className="text-xl font-black text-[#1D1D2B]">Bildirishnomalar</h1>
                        {unreadCount > 0 && (
                            <p className="text-xs text-gray-400">{unreadCount} ta o&apos;qilmagan</p>
                        )}
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    {unreadCount > 0 && (
                        <button
                            onClick={handleMarkAll}
                            className="flex items-center gap-1.5 px-4 py-2 bg-[#f0f4ff] text-[#5377f7] rounded-2xl text-sm font-bold hover:bg-[#e0e8ff] transition"
                        >
                            <CheckCheck size={16} />
                            Hammasini o&apos;qildi
                        </button>
                    )}
                    {notifications.length > 0 && (
                        <button
                            onClick={handleDeleteAll}
                            className="flex items-center justify-center w-10 h-10 bg-[#fff1f1] text-[#ff4d4d] rounded-2xl hover:bg-[#ffe4e4] transition"
                            title="Hammasini o'chirish"
                        >
                            <Trash2 size={18} />
                        </button>
                    )}
                </div>
            </div>

            {/* List */}
            <div className="flex-1 p-4 space-y-3 max-w-2xl mx-auto w-full">
                {loading && (
                    <div className="flex justify-center py-20">
                        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-[#5377f7]" />
                    </div>
                )}

                {!loading && notifications.length === 0 && (
                    <div className="flex flex-col items-center justify-center py-24 gap-4">
                        <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center">
                            <Bell size={36} className="text-gray-300" />
                        </div>
                        <p className="text-gray-400 font-bold text-lg">Bildirishnomalar yo&apos;q</p>
                    </div>
                )}

                {!loading && notifications.map((n) => (
                    <div
                        key={n.id}
                        onClick={() => handleClick(n)}
                        className={`rounded-[24px] p-4 flex items-start gap-4 cursor-pointer transition-all active:scale-[0.98] ${
                            n.is_read ? 'bg-white' : 'bg-[#eef2ff] border border-[#c7d2fe]'
                        }`}
                    >
                        <div className="relative shrink-0">
                            <div className="w-12 h-12 rounded-full bg-[#5377f7] flex items-center justify-center p-2.5">
                                {/* eslint-disable-next-line @next/next/no-img-element */}
                                <img src={NOTIF_LOGO} alt="" className="w-full h-full object-contain" />
                            </div>
                            {!n.is_read && (
                                <div className="absolute -top-0.5 -right-0.5 w-3.5 h-3.5 bg-[#11D76A] rounded-full border-2 border-white" />
                            )}
                        </div>

                        <div className="flex-1 min-w-0">
                            <div className="flex items-center justify-between gap-2 mb-0.5">
                                <span className="text-xs font-bold text-[#5377f7] uppercase tracking-wide">
                                    {typeLabels[n.type] || n.type}
                                </span>
                                <span className="text-xs text-gray-400 shrink-0">{formatTime(n.created_at)}</span>
                            </div>
                            <h3 className={`text-sm font-black text-[#1D1D2B] mb-0.5 ${!n.is_read ? '' : 'font-bold'}`}>
                                {n.title}
                            </h3>
                            <p className="text-sm text-gray-500 line-clamp-2">{n.message}</p>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default NotificationsPage;

'use client';

import { useState, useMemo, type FC } from 'react';
import { ArrowLeft } from 'lucide-react';
import { useTranslations } from 'next-intl';

import { useRouter } from '@/i18n/navigation';
import Qidiruv from '@/components/Bosh sahifa/Qidiruv';
import PatientsTable from '@/components/Bosh sahifa/PatsentTable';
import DoctorPageShell from '@/components/Layout/DoctorPageShell';
import { type Patient } from '@/data/patients';
import { useAllPatients, useCreatePatient } from '@/api/profile';
import { toast } from '@/components/Shared/Toast';
import { paths } from '@/lib/paths';

interface Filters {
  status: string;
  minAge: string;
  maxAge: string;
}

const PatientsPage: FC = () => {
  const t = useTranslations();
  const router = useRouter();
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [filters, setFilters] = useState<Filters>({
    status: 'All',
    minAge: '',
    maxAge: ''
  });

  const { data: apiPatients, isLoading } = useAllPatients();
  const createPatientMutation = useCreatePatient();

  const calculateAge = (birthDate?: string) => {
    if (!birthDate) return 25;
    const birth = new Date(birthDate);
    const now = new Date();
    let age = now.getFullYear() - birth.getFullYear();
    const monthDiff = now.getMonth() - birth.getMonth();
    if (monthDiff < 0 || (monthDiff === 0 && now.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  const patients = useMemo(() => {
    if (!apiPatients || !Array.isArray(apiPatients)) return [];
    return apiPatients.map((p: any) => {
      const status = p.status || 'НОВЫЙ';
      let statusColor = 'text-green-600';

      if (status === 'ЛЕЧИТСЯ') {
        statusColor = 'text-blue-600';
      } else if (status === 'ЗАПИСАН') {
        statusColor = 'text-gray-600';
      }

      return {
        id: p.id,
        name: p.full_name || 'No Name',
        age: calculateAge(p.birth_date),
        phone: p.phone || '',
        diagnosis: p.source === 'doctor_added' ? 'Konsultatsiya' : (p.source || 'Checkup'),
        status: status,
        statusColor: statusColor,
        img: '/assets/img/photos/Subtract.png'
      };
    }) as Patient[];
  }, [apiPatients]);

  const handleAddPatient = async (data: { name: string; phone: string; diagnosis: string }) => {
    try {
      await createPatientMutation.mutateAsync({
        full_name: data.name,
        phone: data.phone,
        source: data.diagnosis
      });
      toast.success(t('patients_list.new_patient_added'));
    } catch (error: any) {
      console.error("Failed to add patient", error);
      const errorMessage = error.response?.data?.detail || "Failed to add patient";
      toast.error(errorMessage);
    }
  };

  const filteredPatients = patients.filter(p => {
    const matchesSearch =
      p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      p.phone.includes(searchQuery) ||
      p.diagnosis.toLowerCase().includes(searchQuery.toLowerCase());

    const matchesStatus = filters.status === 'All' || p.status === filters.status;

    let matchesAge = true;
    if (filters.minAge) matchesAge = matchesAge && p.age >= parseInt(filters.minAge);
    if (filters.maxAge) matchesAge = matchesAge && p.age <= parseInt(filters.maxAge);

    return matchesSearch && matchesStatus && matchesAge;
  });

  if (isLoading) {
    return <div className="flex items-center justify-center min-h-screen">Loading...</div>;
  }

  return (
    <DoctorPageShell
      badge={t('patients.shell.badge')}
      title={t('sidebar.patients')}
      accent={t('patients.shell.accent')}
      description={t('patients.shell.description')}
      contentClassName="p-4 sm:p-6 lg:p-8"
    >
      <div className="mx-auto max-w-6xl">
        <div className="mb-5 flex items-center gap-3 sm:mb-6 sm:gap-4">
          <button
            type="button"
            onClick={() => router.push(paths.menu)}
            className="flex h-11 w-11 shrink-0 items-center justify-center rounded-full border border-[#dfe4ff] bg-[#eef1ff] text-[#5667ff] transition hover:bg-[#e4e9ff]"
            aria-label="Orqaga qaytish"
          >
            <ArrowLeft size={20} />
          </button>
          <div className="min-w-0">
            <p
              className="text-sm font-semibold uppercase tracking-[0.22em] text-[#7080ff]"
              style={{ fontFamily: '"Space Grotesk", sans-serif' }}
            >
              Patient base
            </p>
            <h2
              className="mt-1 text-2xl font-bold text-[#141b33] sm:text-3xl"
              style={{ fontFamily: '"Space Grotesk", sans-serif' }}
            >
              {t('sidebar.patients')}
            </h2>
          </div>
        </div>

        <Qidiruv
          searchQuery={searchQuery}
          setSearchQuery={setSearchQuery}
          onAdd={handleAddPatient}
          onApplyFilter={setFilters}
        />

        <div className="mt-5 sm:mt-6">
          <PatientsTable patients={filteredPatients} />
        </div>
      </div>
    </DoctorPageShell>
  );
};

export default PatientsPage;

'use client';

import { useState, useRef, useEffect } from 'react';
import { ArrowLeft, MapPin, ChevronDown } from 'lucide-react';
import dynamic from 'next/dynamic';
import { useTranslations } from 'next-intl';

import { useRouter } from '@/i18n/navigation';
import { useDentistProfile, useUpdateDentistProfile, useUploadDiploma } from '@/api/profile';
import { toast } from '@/components/Shared/Toast';

const MapModal = dynamic(() => import('@/components/EditDoctorProfile/MapModal'), { ssr: false });

export default function EditDoctorProfilePage() {
  const t = useTranslations();
  const router = useRouter();
  const { data: dentist, refetch } = useDentistProfile();
  const updateProfile = useUpdateDentistProfile();
  const uploadDiploma = useUploadDiploma();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const diplomaInputRef = useRef<HTMLInputElement>(null);
  const [isMapModalOpen, setIsMapModalOpen] = useState(false);
  const [hasPickedLocation, setHasPickedLocation] = useState(false);
  const [coordinates, setCoordinates] = useState({ lat: 41.2995, lng: 69.2401 });
  const [avatar, setAvatar] = useState<string>('/assets/img/photos/Dentist.png');

  const [formData, setFormData] = useState({
    specialization: '',
    education: '',
    phone: '',
    address: '',
    clinic: '',
    birthDate: '',
    experienceYears: '',
    schedule: 'Каждый день',
    workStartHour: '08',
    workStartMinute: '00',
    workEndHour: '16',
    workEndMinute: '00',
    telegram: '',
    instagram: '',
    whatsapp: '',
    gender: '',
  });

  useEffect(() => {
    if (!dentist) return;

    const workHours = dentist.work_hours?.split('-') || ['08:00', '16:00'];
    const [startHour, startMinute] = workHours[0]?.split(':') || ['08', '00'];
    const [endHour, endMinute] = workHours[1]?.split(':') || ['16', '00'];

    setFormData({
      specialization: dentist.specialization || '',
      education: dentist.education || '',
      phone: dentist.phone || '',
      address: dentist.address || '',
      clinic: dentist.clinic || '',
      birthDate: dentist.birth_date ? dentist.birth_date.slice(0, 10) : '',
      experienceYears: dentist.experience_years != null ? String(dentist.experience_years) : '',
      schedule: dentist.schedule || 'Каждый день',
      workStartHour: startHour,
      workStartMinute: startMinute,
      workEndHour: endHour,
      workEndMinute: endMinute,
      telegram: dentist.telegram || '',
      instagram: dentist.instagram || '',
      whatsapp: dentist.whatsapp || '',
      gender: dentist.gender || '',
    });

    if (dentist.latitude && dentist.longitude) {
      setCoordinates({ lat: dentist.latitude, lng: dentist.longitude });
      setHasPickedLocation(true);
    }
  }, [dentist]);

  // value = stored DB string (kept stable across locales); label = translated display text
  const specializations = [
    { value: 'Хирург', label: t('doctor_edit.specs.surgeon') },
    { value: 'Терапевт', label: t('doctor_edit.specs.therapist') },
    { value: 'Ортодонт', label: t('doctor_edit.specs.orthodontist') },
    { value: 'Ортопед', label: t('doctor_edit.specs.orthopedist') },
    { value: 'Пародонтолог', label: t('doctor_edit.specs.periodontist') },
    { value: 'Имплантолог', label: t('doctor_edit.specs.implantologist') },
    { value: 'Общая стоматология', label: t('doctor_edit.specs.general') },
  ];
  const scheduleOptions = [
    { value: 'Каждый день', label: t('doctor_edit.schedules.everyday') },
    { value: 'Будние дни', label: t('doctor_edit.schedules.weekdays') },
    { value: 'Выходные', label: t('doctor_edit.schedules.weekends') },
    { value: 'Понедельник - Пятница', label: t('doctor_edit.schedules.mon_fri') },
    { value: 'Индивидуальный график', label: t('doctor_edit.schedules.custom') },
  ];

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setAvatar(URL.createObjectURL(file));
  };

  const handleDiplomaChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    toast.success(t('doctor_edit.toast_uploading_diploma'));
    try {
      await uploadDiploma.mutateAsync(file);
      await refetch();
      toast.success(t('doctor_edit.toast_diploma_success'));
    } catch (error) {
      console.error('Failed to upload diploma:', error);
      toast.error(t('doctor_edit.toast_diploma_error'));
    }
  };

  const handleMapConfirm = (address: string, lat: number, lng: number) => {
    setFormData((prev) => ({ ...prev, address }));
    setCoordinates({ lat, lng });
    setHasPickedLocation(true);
    setIsMapModalOpen(false);
  };

  const handleSave = async () => {
    try {
      const payload: any = {
        specialization: formData.specialization,
        education: formData.education,
        phone: formData.phone,
        address: formData.address,
        clinic: formData.clinic,
        birth_date: formData.birthDate || null,
        experience_years: formData.experienceYears ? parseInt(formData.experienceYears, 10) : null,
        schedule: formData.schedule,
        work_hours: `${formData.workStartHour}:${formData.workStartMinute}-${formData.workEndHour}:${formData.workEndMinute}`,
        telegram: formData.telegram,
        instagram: formData.instagram,
        whatsapp: formData.whatsapp,
        gender: formData.gender || null,
      };

      if (hasPickedLocation) {
        payload.latitude = coordinates.lat;
        payload.longitude = coordinates.lng;
      }

      await updateProfile.mutateAsync(payload);
      await refetch();
      toast.success(t('doctor_edit.toast_profile_success'));
      setTimeout(() => router.push('/profile'), 1200);
    } catch (error) {
      console.error('Failed to update profile:', error);
      toast.error(t('doctor_edit.toast_profile_error'));
    }
  };

  return (
    <div className="min-h-screen bg-[#F3F6FB] p-6">
      <div className="mx-auto max-w-5xl">
        <div className="mb-8 flex items-center gap-4">
          <button
            onClick={() => router.push('/profile')}
            className="flex h-12 w-12 items-center justify-center rounded-full bg-white shadow-sm hover:bg-gray-50"
          >
            <ArrowLeft className="h-6 w-6" />
          </button>
          <h1 className="text-3xl font-bold">{t('doctor_edit.title')}</h1>
        </div>

        <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
          <div className="space-y-6">
            <div>
              <label className="mb-2 block text-sm text-gray-600">{t('doctor_edit.specialization')}</label>
              <div className="relative">
                <select
                  value={formData.specialization}
                  onChange={(e) => setFormData({ ...formData, specialization: e.target.value })}
                  className="h-14 w-full appearance-none rounded-2xl border-2 border-blue-200 bg-white px-4 text-lg font-semibold focus:border-blue-400 focus:outline-none"
                >
                  <option value="">{t('doctor_edit.not_selected')}</option>
                  {specializations.map((spec) => (
                    <option key={spec.value} value={spec.value}>{spec.label}</option>
                  ))}
                </select>
                <ChevronDown className="pointer-events-none absolute right-4 top-1/2 h-5 w-5 -translate-y-1/2 text-gray-400" />
              </div>
            </div>

            <div className="grid grid-cols-1 gap-4 md:grid-cols-3">
              <div>
                <label className="mb-2 block text-sm text-gray-600">{t('doctor_edit.birth_date')}</label>
                <input
                  type="date"
                  value={formData.birthDate}
                  onChange={(e) => setFormData({ ...formData, birthDate: e.target.value })}
                  className="h-14 w-full rounded-2xl border-2 border-blue-200 bg-white px-4 text-lg font-semibold focus:border-blue-400 focus:outline-none"
                />
              </div>
              <div>
                <label className="mb-2 block text-sm text-gray-600">{t('doctor_edit.experience')}</label>
                <input
                  type="number"
                  min="0"
                  max="80"
                  value={formData.experienceYears}
                  onChange={(e) => setFormData({ ...formData, experienceYears: e.target.value })}
                  className="h-14 w-full rounded-2xl border-2 border-blue-200 bg-white px-4 text-lg font-semibold focus:border-blue-400 focus:outline-none"
                  placeholder="5"
                />
              </div>
              <div>
                <label className="mb-2 block text-sm text-gray-600">{t('doctor_edit.gender')}</label>
                <div className="relative">
                  <select
                    value={formData.gender}
                    onChange={(e) => setFormData({ ...formData, gender: e.target.value })}
                    className="h-14 w-full appearance-none rounded-2xl border-2 border-blue-200 bg-white px-4 text-lg font-semibold focus:border-blue-400 focus:outline-none"
                  >
                    <option value="">{t('doctor_edit.not_selected')}</option>
                    <option value="male">{t('doctor_edit.gender_male')}</option>
                    <option value="female">{t('doctor_edit.gender_female')}</option>
                  </select>
                  <ChevronDown className="pointer-events-none absolute right-4 top-1/2 h-5 w-5 -translate-y-1/2 text-gray-400" />
                </div>
              </div>
            </div>

            <div>
              <label className="mb-2 block text-sm text-gray-600">{t('doctor_edit.phone')}</label>
              <input
                type="tel"
                value={formData.phone}
                onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                className="h-14 w-full rounded-2xl border-2 border-blue-200 bg-white px-4 text-lg font-semibold focus:border-blue-400 focus:outline-none"
                placeholder="+998 93 123 45 67"
              />
            </div>

            <div>
              <label className="mb-2 block text-sm text-gray-600">{t('doctor_edit.address')}</label>
              <div className="group relative">
                <input
                  type="text"
                  value={formData.address}
                  onClick={() => setIsMapModalOpen(true)}
                  className="h-14 w-full cursor-pointer rounded-2xl border-2 border-blue-200 bg-white px-4 pr-28 text-lg font-semibold transition-colors group-hover:border-blue-300 focus:border-blue-400 focus:outline-none"
                  placeholder={t('doctor_edit.address_ph')}
                  readOnly
                />
                <span className="absolute right-11 top-1/2 -translate-y-1/2 text-xs font-bold text-blue-600">{t('doctor_edit.open_map')}</span>
                <MapPin className="pointer-events-none absolute right-4 top-1/2 h-5 w-5 -translate-y-1/2 text-gray-400" />
              </div>
            </div>

            <div>
              <label className="mb-2 block text-sm text-gray-600">{t('doctor_edit.clinic')}</label>
              <input
                type="text"
                value={formData.clinic}
