          </div>

          <div className="space-y-6">
            <div className="flex flex-col items-center gap-4">
              <div className="h-48 w-48 overflow-hidden rounded-3xl bg-gray-200">
                {/* eslint-disable-next-line @next/next/no-img-element */}
                <img src={avatar} alt="Avatar" className="h-full w-full object-cover" />
              </div>
              <input type="file" ref={fileInputRef} onChange={handleAvatarChange} className="hidden" accept="image/*" />
              <button onClick={() => fileInputRef.current?.click()} className="text-lg font-semibold text-blue-600 hover:underline">
                {t('doctor_profile.change_photo')}
              </button>
            </div>

            <div className="rounded-3xl border-2 border-blue-200 bg-white p-6">
              <h3 className="mb-4 text-xl font-bold">{t('doctor_edit.diploma_title')}</h3>
              {dentist?.diploma_photo_url ? (
                <div className="mb-4">
                  <div className="mb-3 h-48 w-full overflow-hidden rounded-xl border border-gray-200 bg-gray-100">
                    {/* eslint-disable-next-line @next/next/no-img-element */}
                    <img src={`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000'}${dentist.diploma_photo_url}`} alt="Diploma" className="h-full w-full object-cover" />
                  </div>
                </div>
              ) : (
                <div className="mb-4 rounded-xl border border-gray-200 bg-gray-50 p-4 text-center text-sm text-gray-500">
                  {t('doctor_edit.diploma_not_uploaded')}
                </div>
              )}

              <input type="file" ref={diplomaInputRef} onChange={handleDiplomaChange} className="hidden" accept="image/*,application/pdf" />
              <button
                onClick={() => diplomaInputRef.current?.click()}
                disabled={uploadDiploma.isPending}
                className="w-full rounded-xl bg-blue-50 py-3 font-bold text-blue-600 transition-colors hover:bg-blue-100 disabled:opacity-50"
              >
                {uploadDiploma.isPending ? t('common.loading') : dentist?.diploma_photo_url ? t('doctor_edit.diploma_upload_new') : t('doctor_edit.diploma_add')}
              </button>
            </div>

            <div>
              <label className="mb-2 block text-sm text-gray-600">Telegram</label>
              <input
                type="text"
                value={formData.telegram}
                onChange={(e) => setFormData({ ...formData, telegram: e.target.value })}
                className="h-14 w-full rounded-2xl border-2 border-blue-200 bg-white px-4 text-lg font-semibold focus:border-blue-400 focus:outline-none"
                placeholder="@stomatolog"
              />
            </div>

            <div>
              <label className="mb-2 block text-sm text-gray-600">Instagram</label>
              <input
                type="text"
                value={formData.instagram}
                onChange={(e) => setFormData({ ...formData, instagram: e.target.value })}
                className="h-14 w-full rounded-2xl border-2 border-blue-200 bg-white px-4 text-lg font-semibold focus:border-blue-400 focus:outline-none"
                placeholder="stomatolog.uz"
              />
            </div>

            <div>
              <label className="mb-2 block text-sm text-gray-600">Whatsapp</label>
              <input
                type="tel"
                value={formData.whatsapp}
                onChange={(e) => setFormData({ ...formData, whatsapp: e.target.value })}
                className="h-14 w-full rounded-2xl border-2 border-blue-200 bg-white px-4 text-lg font-semibold focus:border-blue-400 focus:outline-none"
                placeholder="+998 90 123 45 67"
              />
            </div>
          </div>
        </div>

        <div className="mt-8 flex justify-end">
          <button
            onClick={handleSave}
            disabled={updateProfile.isPending}
            className="rounded-2xl bg-blue-600 px-12 py-4 text-lg font-bold text-white transition-colors hover:bg-blue-700 disabled:opacity-50"
          >
            {updateProfile.isPending ? t('common.saving') : t('common.save')}
          </button>
        </div>
      </div>

      <MapModal
        isOpen={isMapModalOpen}
        onClose={() => setIsMapModalOpen(false)}
        onConfirm={handleMapConfirm}
        initialLat={coordinates.lat}
        initialLng={coordinates.lng}
        initialAddress={formData.address}
      />
    </div>
  );
}

'use client';

import { useState, useRef, useEffect, type FC } from 'react';
import { useSelector } from 'react-redux';
import { useTranslations } from 'next-intl';

import type { RootState } from '@/store/store';
import PageHeader from '@/components/DoctorProfile/PageHeader';
import DoctorInfoCard from '@/components/DoctorProfile/DoctorInfoCard';
import ContactInfoCard from '@/components/DoctorProfile/ContactInfoCard';
import StatsSection from '@/components/DoctorProfile/StatsSection';
import ServicesSection from '@/components/DoctorProfile/ServicesSection';
import WorksSection from '@/components/DoctorProfile/WorksSection';
import ScheduleCard from '@/components/DoctorProfile/ScheduleCard';
import SocialNetworksCard from '@/components/DoctorProfile/SocialNetworksCard';
import { useDentistProfile } from '@/api/profile';

interface ProfileData {
    phone: string;
    email: string;
    address: string;
    education: string;
    clinic: string;
    specialization: string;
    telegram: string;
    instagram: string;
    whatsapp: string;
    schedule: string;
    workStart: string;
    startMinute: string;
    workEnd: string;
    endMinute: string;
    gender: string;
    birthDate: string;
    experienceYears: string;
    name: string;
}

const formatDate = (value?: string | null) => {
    if (!value) return '';
    const date = new Date(value);
    return Number.isNaN(date.getTime()) ? '' : date.toLocaleDateString('ru-RU');
};

const DoctorProfilePage: FC = () => {
    const t = useTranslations();
    const user = useSelector((state: RootState) => state.user.user);
    const { data: dentistData } = useDentistProfile();

    const [profileData, setProfileData] = useState<ProfileData>({
        phone: user?.phone || '+998 (93) 123 45 67',
        email: user?.email || 'example@gmail.com',
        address: t('doctor_profile.address_placeholder'),
        education: '',
        clinic: 'OdontoHub',
        specialization: '',
        telegram: '@stom',
        instagram: 'stomatolog.uz',
        whatsapp: user?.phone || '+998 90 123 45 67',
        schedule: t('doctor_profile.every_day'),
        workStart: '08',
        startMinute: '00',
        workEnd: '16',
        endMinute: '00',
        gender: t('patient_profile.male'),
        birthDate: '',
        experienceYears: '',
        name: user?.full_name || t('common.doctor'),
    });

    useEffect(() => {
        if (!dentistData) return;

        const workHours = dentistData.work_hours?.split('-') || ['08:00', '16:00'];
        const [startHour, startMinute] = workHours[0]?.split(':') || ['08', '00'];
        const [endHour, endMinute] = workHours[1]?.split(':') || ['16', '00'];

        setProfileData((prev) => ({
            ...prev,
            name: dentistData.full_name || prev.name,
            phone: dentistData.phone || prev.phone,
            specialization: dentistData.specialization || prev.specialization,
            education: dentistData.education || prev.education,
            address: dentistData.address || prev.address,
            clinic: dentistData.clinic || prev.clinic,
            schedule: dentistData.schedule || prev.schedule,
            telegram: dentistData.telegram || prev.telegram,
            instagram: dentistData.instagram || prev.instagram,
            whatsapp: dentistData.whatsapp || prev.whatsapp,
            workStart: startHour,
            startMinute,
            workEnd: endHour,
            endMinute,
            birthDate: formatDate(dentistData.birth_date),
            experienceYears: dentistData.experience_years != null ? `${dentistData.experience_years} ${t('doctor_profile.experience_suffix')}` : '',
            gender: dentistData.gender === 'male'
                ? t('patient_profile.male')
                : dentistData.gender === 'female'
                    ? t('patient_profile.female')
                    : prev.gender,
        }));
    }, [dentistData, t]);

    useEffect(() => {
        if (!user) return;
        setProfileData((prev) => ({
            ...prev,
            name: user.full_name || prev.name,
            phone: user.phone || prev.phone,
            email: user.email || prev.email,
            whatsapp: user.phone || prev.whatsapp,
        }));
    }, [user]);

    const [avatarUrl, setAvatarUrl] = useState<string>('/assets/img/photos/Dentist.png');
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleUpdateProfile = (newData: Partial<ProfileData>) => {
        setProfileData((prev) => ({ ...prev, ...newData }));
    };

    const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        setAvatarUrl(URL.createObjectURL(file));
    };

    const triggerAvatarUpload = () => {
        fileInputRef.current?.click();
    };

    return (
        <div className="min-h-screen bg-[#F3F6FB]">
            <div className="mx-auto max-w-[1440px] px-4 py-4 sm:px-6 sm:py-6">
                <PageHeader />

                <div className="mt-6 space-y-6 sm:mt-8 sm:space-y-8">
                    <input type="file" ref={fileInputRef} onChange={handleAvatarChange} className="hidden" accept="image/*" />

                    <div className="grid grid-cols-1 gap-6 lg:grid-cols-12 lg:gap-8">
                        <div className="lg:col-span-12 xl:col-span-4">
                            <DoctorInfoCard
                                name={profileData.name}
                                specialization={profileData.specialization}
                                gender={profileData.gender}
                                birthDate={profileData.birthDate}
                                experienceYears={profileData.experienceYears}
                                avatar={avatarUrl}
                                onAvatarClick={triggerAvatarUpload}
                            />
                        </div>
                        <div className="lg:col-span-12 xl:col-span-8">
                            <ContactInfoCard data={profileData} onSave={handleUpdateProfile} avatar={avatarUrl} triggerAvatarUpload={triggerAvatarUpload} />
                        </div>
                    </div>

                    <StatsSection />
                    <ServicesSection />
                    <WorksSection />

                    <div className="grid grid-cols-1 gap-6 pb-10 lg:grid-cols-2 lg:gap-8 lg:pb-12">
                        <ScheduleCard
                            workStart={profileData.workStart}
                            startMinute={profileData.startMinute}
                            workEnd={profileData.workEnd}
                            endMinute={profileData.endMinute}
                            onSave={handleUpdateProfile}
                        />
                        <SocialNetworksCard telegram={profileData.telegram} instagram={profileData.instagram} whatsapp={profileData.whatsapp} />
                    </div>
                </div>
            </div>
        </div>
    );
};

export default DoctorProfilePage;

