'use client';

import { useState, useEffect, useMemo } from 'react';
import { useAllDentists } from '@/api/profile';
import { useMyAppointments } from '@/api/appointments';
import { Link, useRouter } from '@/i18n/navigation';
import { paths } from '@/lib/paths';
import { MapPin } from 'lucide-react';
import DoctorName from '@/components/Shared/DoctorName';

const DOCTOR_IMG = '/assets/img/photos/Dentist.png';

export default function SuggestedDoctors() {
  const router = useRouter();
  const { data: dentists, isLoading: isLoadingDentists } = useAllDentists();
  const { data: appointments, isLoading: isLoadingAppointments } = useMyAppointments();
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    const storedLocation = localStorage.getItem('user_location');
    if (storedLocation) {
      setUserLocation(JSON.parse(storedLocation));
    } else {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          const loc = { lat: pos.coords.latitude, lng: pos.coords.longitude };
          setUserLocation(loc);
          localStorage.setItem('user_location', JSON.stringify(loc));
        },
        (err) => console.log('Geolocation error:', err)
      );
    }
  }, []);

  const getDistance = (lat1: number, lon1: number, lat2: number, lon2: number) => {
    const R = 6371;
    const dLat = ((lat2 - lat1) * Math.PI) / 180;
    const dLon = ((lon2 - lon1) * Math.PI) / 180;
    const a =
      Math.sin(dLat / 2) * Math.sin(dLat / 2) +
      Math.cos((lat1 * Math.PI) / 180) * Math.cos((lat2 * Math.PI) / 180) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
  };

  const suggestedDoctors = useMemo(() => {
    if (!dentists) return [];
    let list = [...dentists];
    if (userLocation) {
      list = list
        .map((d: any) => {
          const lat = Number(d.latitude);
          const lng = Number(d.longitude);
          const dist =
            Number.isFinite(lat) && Number.isFinite(lng) && lat !== 0 && lng !== 0
              ? getDistance(userLocation.lat, userLocation.lng, lat, lng)
              : null;
          return { ...d, distance: dist };
        })
        .sort((a: any, b: any) => {
          if (a.distance === null || a.distance === undefined) return 1;
          if (b.distance === null || b.distance === undefined) return -1;
          return a.distance - b.distance;
        });
    }
    return list.slice(0, 5);
  }, [dentists, userLocation]);

  const isLoading = isLoadingDentists || isLoadingAppointments;
  const hasUpcomingAppointments = appointments && appointments.length > 0;

  if (isLoading) {
    return (
      <div className="animate-pulse space-y-4">
        <div className="h-8 w-48 bg-gray-200 rounded-lg" />
        <div className="flex gap-4 overflow-hidden">
          {[1, 2, 3].map((i) => (
            <div key={i} className="min-w-[200px] h-[280px] bg-gray-100 rounded-3xl" />
          ))}
        </div>
      </div>
    );
  }

  if (!dentists || dentists.length === 0 || hasUpcomingAppointments) return null;

  const goToBooking = (doctor: any) => {
    if (typeof window !== 'undefined') {
      sessionStorage.setItem(
        'gosmile:booking_doctor',
        JSON.stringify({
          ...doctor,
          name: doctor.full_name,
          direction: doctor.specialization || 'Stomatolog',
          image: DOCTOR_IMG,
          specialty: doctor.specialization || 'Umumiy stomatologiya',
          experience: doctor.experience_years ? `${doctor.experience_years} yil tajriba` : '',
          rating: doctor.rating || '5.0',
        })
      );
    }
    router.push(paths.booking);
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between px-2">
        <div className="flex items-center gap-2">
          <h2 className="text-2xl font-black text-gray-900 leading-tight font-serif tracking-tight">
            Sizga yaqin shifokorlar
          </h2>
          {userLocation && <MapPin size={18} className="text-blue-500 animate-bounce" />}
        </div>
        <Link href={paths.doctors} className="text-blue-600 font-bold hover:underline">
          Barchasi
        </Link>
      </div>

      <div className="flex gap-4 overflow-x-auto pb-4 no-scrollbar -mx-2 px-2">
        {suggestedDoctors.map((doctor: any) => (
          <div
            key={doctor.id}
            onClick={() => goToBooking(doctor)}
            className="min-w-[260px] bg-white border border-gray-100 rounded-[32px] p-6 text-gray-900 shadow-xl shadow-blue-500/5 cursor-pointer transition-all hover:scale-[1.02] hover:shadow-blue-500/10 active:scale-95 group"
          >
            <div className="relative mb-4">
              <div className="bg-blue-50 rounded-[24px] w-24 h-24 overflow-hidden flex items-center justify-center group-hover:bg-blue-100 transition-colors">
                {/* eslint-disable-next-line @next/next/no-img-element */}
                <img src={DOCTOR_IMG} alt={doctor.full_name} className="w-full h-full object-cover" />
              </div>
              {doctor.distance !== null && doctor.distance !== undefined && (
                <div className="absolute -right-2 -bottom-2 bg-[#4D71F8] text-white px-3 py-1 rounded-full text-[10px] font-black shadow-lg">
                  {Number(doctor.distance).toFixed(1)} km
                </div>
              )}
            </div>
            <DoctorName
              name={doctor.full_name}
              className="block text-xl font-black mb-1 truncate text-blue-900"
              placeholderClassName="block text-sm font-bold mb-1 text-gray-400"
            />
            <p className="text-gray-500 text-sm mb-4 font-semibold">{doctor.specialization || 'Stomatolog'}</p>
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-1 bg-yellow-50 rounded-full px-2 py-1 text-xs font-black text-yellow-600">
                <span>⭐</span>
                <span>{doctor.rating || '5.0'}</span>
              </div>
              <span className="text-sm font-black text-blue-600 group-hover:translate-x-1 transition-transform">Band qilish →</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

'use client';

import { useState, useMemo } from 'react';
import { useSearchParams } from 'next/navigation';
import { useRouter } from '@/i18n/navigation';
import { ChevronLeft, Search, User, Stethoscope, ArrowUpDown } from 'lucide-react';
import { useSearchDoctors, useSearchServices } from '@/api/search';
import DoctorCard from '@/components/Doctors/DoctorCard';
import { paths } from '@/lib/paths';
import type { Doctor } from '@/types/patient';

const DoctorImg = "/assets/img/photos/Dentist.png";

const SearchResultsView = () => {
    const searchParams = useSearchParams();
    const query = searchParams.get('q') || '';
    const router = useRouter();
    const [activeTab, setActiveTab] = useState<'doctors' | 'services'>('doctors');
    const [priceOrder, setPriceOrder] = useState<'asc' | 'desc' | null>(null);

    const { data: doctors, isLoading: loadingDocs } = useSearchDoctors(query);
    const { data: services, isLoading: loadingServices } = useSearchServices(query);

    const sortedServices = useMemo(() => {
        if (!services) return [];
        const result = [...services];
        if (priceOrder === 'asc') {
            result.sort((a, b) => a.price - b.price);
        } else if (priceOrder === 'desc') {
            result.sort((a, b) => b.price - a.price);
        }
        return result;
    }, [services, priceOrder]);

    const handleBook = (doctor: Doctor) => {
        if (typeof window !== 'undefined') {
            sessionStorage.setItem('gosmile:booking_doctor', JSON.stringify(doctor));
        }
        router.push(paths.booking);
    };

    const handleOpenMap = (doctor: Doctor) => {
        // Option 1: Open map modale here if defined
        // Option 2: Just ignore or show alert
        console.log("Open map for", doctor.name);
    };

    return (
        <div className="min-h-screen bg-gray-50">
            {/* Header */}
            <div className="bg-white px-4 py-4 sticky top-0 z-10 shadow-sm">
                <div className="flex items-center gap-3">
                    <button onClick={() => router.back()} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
                        <ChevronLeft size={24} className="text-gray-700" />
                    </button>
                    <div className="flex-1 bg-gray-100 rounded-2xl flex items-center px-4 py-2 gap-2">
                        <Search size={18} className="text-gray-400" />
                        <span className="text-gray-700 font-bold">{query}</span>
                    </div>
                </div>

                {/* Tabs */}
                <div className="flex mt-4 bg-gray-100 p-1 rounded-xl">
                    <button
                        onClick={() => setActiveTab('doctors')}
                        className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg font-bold text-sm transition-all ${
                            activeTab === 'doctors' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500'
                        }`}
                    >
                        <User size={16} />
                        Shifokorlar ({doctors?.length || 0})
                    </button>
                    <button
                        onClick={() => setActiveTab('services')}
                        className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg font-bold text-sm transition-all ${
                            activeTab === 'services' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500'
                        }`}
                    >
                        <Stethoscope size={16} />
                        Xizmatlar ({services?.length || 0})
                    </button>
                </div>
            </div>

            {/* Content */}
            <div className="p-4">
                {activeTab === 'doctors' ? (
                    <div className="space-y-4">
                        {loadingDocs ? (
                            <div className="flex justify-center py-10"><div className="animate-spin rounded-full h-10 w-10 border-b-2 border-blue-600" /></div>
                        ) : doctors && doctors.length > 0 ? (
                            doctors.map((doc: any) => (
                                <DoctorCard
                                    key={doc.id}
                                    doctor={{
                                        ...doc,
                                        name: doc.full_name,
                                        direction: doc.specialization,
                                        experience: `${doc.experience_years} yil tajriba`,
                                        image: DoctorImg
                                    }}
                                    onBook={() => handleBook(doc)}
                                    onOpenMap={() => handleOpenMap(doc)}
                                />
                            ))
                        ) : (
                            <div className="text-center py-20 text-gray-400">
                                <Search size={48} className="mx-auto mb-4 opacity-20" />
                                <p className="font-bold">Shifokorlar topilmadi</p>
                            </div>
                        )}
                    </div>
                ) : (
                    <div className="space-y-4">
                        {/* Service Sort Toggle */}
                        {services && services.length > 0 && (
                            <div className="flex justify-end">
                                <button
                                    onClick={() => setPriceOrder(prev => prev === 'asc' ? 'desc' : 'asc')}
                                    className="flex items-center gap-2 bg-white px-4 py-2 rounded-xl text-sm font-bold text-gray-700 shadow-sm border border-gray-100 active:scale-95 transition-all"
                                >
                                    <ArrowUpDown size={16} className="text-blue-500" />
                                    Narx bo'yicha: {priceOrder === 'asc' ? 'Arzon' : priceOrder === 'desc' ? 'Qimmat' : 'Saralash'}
                                </button>
                            </div>
                        )}

                        {loadingServices ? (
                            <div className="flex justify-center py-10"><div className="animate-spin rounded-full h-10 w-10 border-b-2 border-blue-600" /></div>
                        ) : sortedServices.length > 0 ? (
                            sortedServices.map(service => (
                                <div key={service.id} className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100 flex justify-between items-center group transition-all hover:shadow-md">
                                    <div className="flex-1">
                                        <h3 className="font-black text-blue-900 text-lg group-hover:text-blue-600 transition-colors uppercase tracking-tight">{service.name}</h3>
                                        <div className="flex items-center gap-4 mt-2">
                                            <div className="flex items-center gap-1.5 text-gray-500 bg-gray-50 px-3 py-1 rounded-full text-xs font-bold">
                                                <User size={14} className="text-blue-500" />
                                                <span>{service.dentist_name || "Shifokor"}</span>
                                            </div>
                                            <div className="text-blue-600 font-black text-lg">
                                                {service.price.toLocaleString()} so'm
                                            </div>
                                        </div>
                                    </div>
                                    <button
                                        onClick={() => router.push(paths.doctors)}
                                        className="bg-blue-50 text-blue-600 font-bold px-4 py-2 rounded-2xl text-sm hover:bg-blue-600 hover:text-white transition-all active:scale-95"
                                    >
                                        Band qilish
                                    </button>
                                </div>
                            ))
                        ) : (
                            <div className="text-center py-20 text-gray-400">
                                <Search size={48} className="mx-auto mb-4 opacity-20" />
                                <p className="font-bold">Xizmatlar topilmadi</p>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

export default SearchResultsView;

