'use client';

import { useEffect, useState, type ReactNode } from 'react';
import { useRouter } from '@/i18n/navigation';

type Role = 'patient' | 'dentist';

interface RoleGuardProps {
  requiredRole?: Role;
  children: ReactNode;
}

export function RoleGuard({ requiredRole, children }: RoleGuardProps) {
  const router = useRouter();
  const [ready, setReady] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('access_token');
    if (!token) {
      router.replace('/login');
      return;
    }
    const userRaw = localStorage.getItem('user_data');
    let user: { role?: Role } | null = null;
    try {
      user = userRaw ? JSON.parse(userRaw) : null;
    } catch {
      user = null;
    }
    if (requiredRole && user?.role !== requiredRole) {
      router.replace('/role');
      return;
    }
    setReady(true);
  }, [requiredRole, router]);

  if (!ready) return null;
  return <>{children}</>;
}

'use client';

import React, { useEffect, useState } from "react";
import { Bell, Calendar, LayoutDashboard, Menu, MessageCircle, Users, X } from "lucide-react";
import { useTranslations } from "next-intl";

import { Link, usePathname } from "@/i18n/navigation";
import { useMyAppointments } from "@/api/appointments";
import { useUnreadCount } from "@/api/notifications";
import { useAllPatients } from "@/api/profile";
import { paths } from "@/lib/paths";

type MenuItem = {
  id: string;
  label: string;
  icon: React.ComponentType<{ size?: number; strokeWidth?: number; className?: string }>;
  path: string;
};

export default function Sidebar() {
  const pathname = usePathname();
  const [isMobileOpen, setIsMobileOpen] = useState(false);
  const t = useTranslations();

  const { data: appointments } = useMyAppointments();
  const { data: patients } = useAllPatients();
  const { data: unreadCount = 0 } = useUnreadCount();

  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const tomorrow = new Date(today);
  tomorrow.setDate(tomorrow.getDate() + 1);

  const todayAppointments = appointments?.filter((apt: any) => {
    const aptDate = new Date(apt.start_time);
    return aptDate >= today && aptDate < tomorrow;
  }).length || 0;

  const newPatientsToday = patients?.filter((patient: any) => {
